Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file. This program is case-insensitive and considers whole words only (not substrings within other words):

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <sstream>
#include <cctype>
#include <algorithm>

// Function to convert a string to lowercase
std::string toLower(const std::string& str) {
    std::string lowerStr = str;
    std::transform(lowerStr.begin(), lowerStr.end(), lowerStr.begin(),
                   [](unsigned char c) { return std::tolower(c); });
    return lowerStr;
}

// Function to check if a word is present in a given line
bool containsWord(const std::string& line, const std::string& word) {
    std::istringstream iss(line);
    std::string temp;
    while (iss >> temp) {
        if (toLower(temp) == toLower(word)) {
            return true;
        }
    }
    return false;
}

int main() {
    std::string filename;
    std::string wordToFind;
    int count = 0;

    // Ask the user for the file name and the word to search for
    std::cout << "Enter the file name: ";
    std::cin >> filename;
    std::cout << "Enter the word to search for: ";
    std::cin >> wordToFind;

    // Open the file
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error opening file." << std::endl;
        return 1;
    }

    // Read the file line by line
    std::string line;
    while (std::getline(file, line)) {
        if (containsWord(line, wordToFind)) {
            ++count;
        }
    }

    // Close the file
    file.close();

    // Output the result
    std::cout << "The word '" << wordToFind << "' occurs " << count << " times in the file." << std::endl;

    return 0;
}
```

To compile and run this program, follow these steps:

1. Save the code to a file, for example, `word_count.cpp`.
2. Open a terminal or command prompt.
3. Compile the program using a C++ compiler, such as g++:
   ```
   g++ -o word_count word_count.cpp
   ```
4. Run the compiled program:
   ```
   ./word_count
   ```
   or on Windows:
   ```
   word_count.exe
   ```
5. Enter the file name and the word you want to search for when prompted.

Make sure the text file you want to search through is in the same directory as the executable or provide the correct path to the file when prompted.
